import{c as r,Q as t,j as a,m as o}from"./chunks/framework.4b-lwRvT.js";const b=JSON.parse('{"title":"我该从哪里开始？","description":"","frontmatter":{"title":"我该从哪里开始？"},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1779684191000}'),i={name:"guide/index.md"};function d(l,e,n,m,h,s){return t(),a("div",null,[...e[0]||(e[0]=[o('<p>不管你是第一次来还是老朋友，这里帮你快速找到感兴趣的内容。</p><h2 id="按身份定位" tabindex="-1">按身份定位 <a class="header-anchor" href="#按身份定位" aria-label="Permalink to &quot;按身份定位&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你是谁</th><th>建议从这里</th></tr></thead><tbody><tr><td>想学 C++ 的嵌入式开发者</td><td><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_AwesomeModernCPP" target="_blank" rel="noreferrer">Tutorial_AwesomeModernCPP</a> — 从 C++11 到 C++23 的系统教程</td></tr><tr><td>想学 Qt / GUI 开发</td><td><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_AwesomeQt" target="_blank" rel="noreferrer">Tutorial_AwesomeQt</a> — Qt 6 百科全书式教程</td></tr><tr><td>想玩 Embedded Linux</td><td><a href="https://github.com/Awesome-Embedded-Learning-Studio/imx-forge" target="_blank" rel="noreferrer">imx-forge</a> — i.MX6ULL BSP 快速部署</td></tr><tr><td>想做 MCU 裸机项目</td><td><a href="https://github.com/Awesome-Embedded-Learning-Studio/BareMetal-Drivers" target="_blank" rel="noreferrer">BareMetal-Drivers</a> — 通用裸机驱动库</td></tr><tr><td>想参与贡献</td><td><a href="/Awesome-Embedded/contributing/">贡献指南</a></td></tr><tr><td>只想随便看看</td><td><a href="/Awesome-Embedded/projects/">项目一览</a></td></tr></tbody></table><h2 id="四条主航道" tabindex="-1">四条主航道 <a class="header-anchor" href="#四条主航道" aria-label="Permalink to &quot;四条主航道&quot;">​</a></h2><p>我们的学习和建设围绕四条主线展开：</p><h3 id="_1-c-的入门学习与进一步工程化" tabindex="-1">1. C++ 的入门学习与进一步工程化 <a class="header-anchor" href="#_1-c-的入门学习与进一步工程化" aria-label="Permalink to &quot;1. C++ 的入门学习与进一步工程化&quot;">​</a></h3><p>从手搓 INI 解析器到现代 C++ 全栈教程，目标是让嵌入式开发者和任何 C++ 初步入门的爱好者也能写出工程级的 C++ 代码。</p><ul><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_AwesomeModernCPP" target="_blank" rel="noreferrer">Tutorial_AwesomeModernCPP</a> — 现代 C++ 系统教程（C++11~C++23）</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Project_CXXBaseComponents" target="_blank" rel="noreferrer">Project_CXXBaseComponents</a> — B 站动画系列 C++ 基础组件源码</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/miniwget" target="_blank" rel="noreferrer">miniwget</a> — 轻量级 HTTP 下载工具，C++ 工程化教学项目（敬请期待）</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_cpp_SimpleIniParser" target="_blank" rel="noreferrer">Tutorial_cpp_SimpleIniParser</a> — 手搓最简 INI 解析器</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Project_MakeAMemroyPool" target="_blank" rel="noreferrer">Project_MakeAMemroyPool</a> — 配合视频的内存池实战</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/CFBox" target="_blank" rel="noreferrer">CFBox</a> — C++23 极简 BusyBox</li></ul><h3 id="_2-embedded-linux" tabindex="-1">2. Embedded Linux <a class="header-anchor" href="#_2-embedded-linux" aria-label="Permalink to &quot;2. Embedded Linux&quot;">​</a></h3><p>从 i.MX6ULL BSP 到 RK 芯片适配，从内核到用户空间的动手实验。</p><ul><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/imx-forge" target="_blank" rel="noreferrer">imx-forge</a> — i.MX6ULL BSP 补丁快速部署</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/rk-forge" target="_blank" rel="noreferrer">rk-forge</a> — Rockchip 系列 BSP 补丁</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/PenguinLab" target="_blank" rel="noreferrer">PenguinLab</a> — 嵌入式 Linux 全栈动手实验</li></ul><h3 id="_3-mcu-裸机-freertos" tabindex="-1">3. MCU / 裸机 / FreeRTOS <a class="header-anchor" href="#_3-mcu-裸机-freertos" aria-label="Permalink to &quot;3. MCU / 裸机 / FreeRTOS&quot;">​</a></h3><p>STM32 HAL 驱动、裸机驱动库、FreeRTOS 教程，专注资源受限平台。</p><ul><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/ST-Forge" target="_blank" rel="noreferrer">ST-Forge</a> — STM32 HAL 驱动框架，CMake 原生构建</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/BareMetal-Drivers" target="_blank" rel="noreferrer">BareMetal-Drivers</a> — 单片机裸机通用驱动库</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Project_MicroWatch" target="_blank" rel="noreferrer">Project_MicroWatch</a> — 资源受限平台智能手表</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_FreeRTOS" target="_blank" rel="noreferrer">Tutorial_FreeRTOS</a> — FreeRTOS 系列教程（正在规划激活中）</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/micro-forge" target="_blank" rel="noreferrer">micro-forge</a> — ARM Cortex-M3 (STM32F103) 全系统模拟器，无需硬件即可运行和调试固件</li></ul><h3 id="_4-qt-gui-产品化" tabindex="-1">4. Qt / GUI / 产品化 <a class="header-anchor" href="#_4-qt-gui-产品化" aria-label="Permalink to &quot;4. Qt / GUI / 产品化&quot;">​</a></h3><p>从 Qt 教程到嵌入式桌面框架，把学习成果变成可以展示的产品。</p><ul><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_AwesomeQt" target="_blank" rel="noreferrer">Tutorial_AwesomeQt</a> — Qt 6 百科全书式教程</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/CFDesktop" target="_blank" rel="noreferrer">CFDesktop</a> — 嵌入式设备 Material Design 3 桌面框架</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/qt-compile-pipeline" target="_blank" rel="noreferrer">qt-compile-pipeline</a> — Qt6 ARM 交叉编译自动化管道</li></ul><h3 id="实验项目" tabindex="-1">实验项目 <a class="header-anchor" href="#实验项目" aria-label="Permalink to &quot;实验项目&quot;">​</a></h3><p>这些项目处于早期探索阶段：</p><ul><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/edgecv" target="_blank" rel="noreferrer">edgecv</a> — 嵌入式边缘计算机视觉库，Header-Only</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/bareline" target="_blank" rel="noreferrer">bareline</a> — 轻量级 CLI 交互框架（敬请期待）</li><li><a href="https://github.com/Awesome-Embedded-Learning-Studio/Tutorial_EmbeddedCommonTools" target="_blank" rel="noreferrer">Tutorial_EmbeddedCommonTools</a> — 嵌入式开发通用工具教程（正在规划激活中）</li></ul><h2 id="还在犹豫" tabindex="-1">还在犹豫？ <a class="header-anchor" href="#还在犹豫" aria-label="Permalink to &quot;还在犹豫？&quot;">​</a></h2><blockquote><p>Keep it small, make it fun.</p></blockquote><p>随便挑一个感兴趣的项目开始，遇到问题就开 Issue，想聊天就来 Discussions。我们不需要你做好准备再来 —— 来了就是准备。</p>',23)])])}const g=r(i,[["render",d]]);export{b as __pageData,g as default};
